18.     internal readonly struct DiagnosticScope : IDisposable
19.     {
20.         private const string AzureSdkScopeLabel = "az.sdk.scope";
21.         internal const string OpenTelemetrySchemaAttribute = "az.schema_url";
22. 
23.         // we follow OpenTelemtery Semantic Conventions 1.23.0
24.         // https://github.com/open-telemetry/semantic-conventions/blob/v1.23.0
25.         internal const string OpenTelemetrySchemaVersion = "https://opentelemetry.io/schemas/1.23.0";
