54. 
55.         public void AddAttribute(string name, string? value)
56.         {
57.             if (value != null)
58.             {
59.                 _activityAdapter?.AddTag(name, value);
60.             }
61.         }
62. 
63.         public void AddIntegerAttribute(string name, int value)
64.         {
65.             _activityAdapter?.AddTag(name, value);
66.         }
67. 
