266.             public Activity? Start()
267.             {
268.                 _currentActivity = StartActivitySourceActivity();
269.                 if (_currentActivity != null)
270.                 {
271.                     if (!_currentActivity.IsAllDataRequested)
272.                     {
273.                         _sampleOutActivity = _currentActivity;
274.                         _currentActivity = null;
275. 
276.                         return null;
277.                     }
278. 
279.                     _currentActivity.SetTag(OpenTelemetrySchemaAttribute, OpenTelemetrySchemaVersion);
280.                 }
281.                 else
282.                 {
283.                     if (!_diagnosticSource.IsEnabled(_activityName, _diagnosticSourceArgs))
284.                     {
285.                         return null;
286.                     }
287. 
288.                     switch (_kind)
289.                     {
290.                         case ActivityKind.Internal:
291.                             AddTag("kind", "internal");
292.                             break;
293.                         case ActivityKind.Server:
294.                             AddTag("kind", "server");
295.                             break;
296.                         case ActivityKind.Client:
297.                             AddTag("kind", "client");
298.                             break;
299.                         case ActivityKind.Producer:
300.                             AddTag("kind", "producer");
301.                             break;
302.                         case ActivityKind.Consumer:
303.                             AddTag("kind", "consumer");
304.                             break;
305.                     }
306. 
307.                     _currentActivity = new DiagnosticActivity(_activityName)
308.                     {
309.                         Links = GetDiagnosticSourceLinkCollection(),
310.                     };
311.                     _currentActivity.SetIdFormat(ActivityIdFormat.W3C);
312. 
313.                     if (_startTime != default)
314.                     {
315.                         _currentActivity.SetStartTime(_startTime.UtcDateTime);
316.                     }
317. 
318.                     if (_tagCollection != null)
319.                     {
320.                         foreach (var tag in _tagCollection)
321.                         {
322.                             AddObjectTag(tag.Key, tag.Value!);
323.                         }
324.                     }
325. 
326.                     if (_traceparent != null)
327.                     {
328.                         _currentActivity.SetParentId(_traceparent);
329.                     }
330. 
331.                     if (_tracestate != null)
332.                     {
333.                         _currentActivity.TraceStateString = _tracestate;
334.                     }
335. 
336.                     _currentActivity.Start();
337.                 }
338. 
339.                 if (_displayName != null)
340.                 {
341.                     _currentActivity.DisplayName = _displayName;
342.                 }
343. 
344.                 return _currentActivity;
345.             }
346. 
347.             public void SetDisplayName(string displayName)
348.             {
349.                 _displayName = displayName;
350.                 if (_currentActivity != null)
351.                 {
352.                     _currentActivity.DisplayName = _displayName;
353.                 }
354.             }
355. 
356.             private Activity? StartActivitySourceActivity()
357.             {
358.                 if (_activitySource == null)
359.                 {
360.                     return null;
361.                 }
362.                 // TODO(limolkova) set isRemote to true once we switch to DiagnosticSource 7.0
363.                 ActivityContext.TryParse(_traceparent, _tracestate, out ActivityContext context);
364.                 return _activitySource.StartActivity(_activityName, _kind, context, _tagCollection, _links, _startTime);
365.             }
366. 
367.             public void SetStartTime(DateTime startTime)
368.             {
369.                 _startTime = startTime;
370.                 _currentActivity?.SetStartTime(startTime);
371.             }
372. 
373.             public void MarkFailed<T>(T? exception, string? errorCode)
374.             {
375.                 if (errorCode == null && exception != null)
376.                 {
377.                     errorCode = exception.GetType().FullName;
378.                 }
379. 
380.                 errorCode ??= "_OTHER";
381. 
382.                 // SetStatus is only defined in NET 6 or greater
383.                 _currentActivity?.SetTag("error.type", errorCode);
384.                 _currentActivity?.SetStatus(ActivityStatusCode.Error, exception?.ToString());
385.             }
386. 
387.             public void SetTraceContext(string traceparent, string? tracestate)
388.             {
389.                 if (_currentActivity != null)
390.                 {
391.                     throw new InvalidOperationException("Traceparent can not be set after the activity is started.");
392.                 }
393.                 _traceparent = traceparent;
394.                 _tracestate = tracestate;
395.             }
396. 
397.             private void AddObjectTag(string name, object value)
398.             {
399.                 if (_activitySource?.HasListeners() == true)
400.                 {
401.                     _currentActivity?.SetTag(name, value);
402.                 }
403.                 else
404.                 {
405.                     _currentActivity?.AddTag(name, value.ToString());
406.                 }
407.             }
408. 
409.             public void Dispose()
410.             {
411.                 var activity = _currentActivity ?? _sampleOutActivity;
412.                 if (activity == null)
413.                 {
414.                     return;
415.                 }
416. 
417.                 if (activity.Duration == TimeSpan.Zero)
418.                     activity.SetEndTime(DateTime.UtcNow);
419. 
420.                 activity.Dispose();
421. 
422.                 _currentActivity = null;
423.                 _sampleOutActivity = null;
424.             }
425.         }
426.     }
