                 }
             }

             public void Dispose()
             {
                 var activity = _currentActivity ?? _sampleOutActivity;
                 if (activity == null)
                 {
                     return;
                 }

                 if (activity.Duration == TimeSpan.Zero)
                     activity.SetEndTime(DateTime.UtcNow);

                 activity.Dispose();

