             var output = new char[value.Length + paddingCharsToAdd];

             int i;
             for (i = 0; i < value.Length; i++)
             {
                 var ch = value[i];
                 if (ch == '-')
                 {
                     output[i] = '+';
                 }
                 else if (ch == '_')
                 {
                     output[i] = '/';
                 }
                 else
